// ============================================================
// src/components/admin/BillingTab.js
// ============================================================
import React, { useState, useEffect, useCallback } from "react";
import api from "../../utils/api";

const HOSPITAL_NAME = "PearlSmile Dental Hospital";
const HOSPITAL_ADDRESS = "Dental Care Centre, Maharashtra, India";
const HOSPITAL_PHONE = "+91 87936 08083";
const HOSPITAL_GST = "GST: 27XXXXX1234X1Z5";

const DENTAL_TREATMENTS = [
  "General Checkup & Cleaning",
  "Teeth Whitening",
  "Dental Implant",
  "Root Canal Therapy",
  "Crown / Cap",
  "Bridge",
  "Orthodontic Treatment (Braces)",
  "Invisalign",
  "Tooth Extraction",
  "Wisdom Tooth Removal",
  "Composite Filling",
  "Amalgam Filling",
  "Dental X-Ray",
  "Scaling & Polishing",
  "Gum Treatment (Periodontics)",
  "Smile Makeover",
  "Veneer",
  "Pediatric Dentistry",
  "Fluoride Treatment",
  "Mouthguard / Night Guard",
  "Consultation Fee",
  "Follow-Up Visit",
  "Oral Surgery",
  "Jaw Treatment (TMJ)",
  "Emergency Dental Care",
];

const PAYMENT_METHODS = [
  { value: "cash", label: "Cash" },
  { value: "upi", label: "UPI" },
  { value: "card", label: "Card" },
  { value: "insurance", label: "Insurance" },
  { value: "other", label: "Other" },
];

const STATUS_CONFIG = {
  paid: { label: "Paid", color: "#16a34a", bg: "#f0fdf4" },
  partial: { label: "Partial", color: "#d97706", bg: "#fffbeb" },
  unpaid: { label: "Unpaid", color: "#dc2626", bg: "#fef2f2" },
};

// ---- Helpers ------------------------------------------------
function fmtMoney(n) {
  return (
    "Rs. " +
    Number(n || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })
  );
}

function todayISO() {
  return new Date().toISOString().split("T")[0];
}

function friendlyDate(d) {
  if (!d) return "--";
  var dt = new Date(d + "T00:00:00");
  if (isNaN(dt.getTime())) return d;
  return dt.toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

function calcTotals(items, discountType, discountValue, gstPercent) {
  var subtotal = items.reduce(function (s, i) {
    return s + (parseFloat(i.amount) || 0);
  }, 0);
  var discountAmount =
    discountType === "percent"
      ? (subtotal * (parseFloat(discountValue) || 0)) / 100
      : parseFloat(discountValue) || 0;
  var afterDiscount = Math.max(0, subtotal - discountAmount);
  var gstAmount = (afterDiscount * (parseFloat(gstPercent) || 0)) / 100;
  var totalAmount = afterDiscount + gstAmount;
  return {
    subtotal: subtotal,
    discountAmount: discountAmount,
    gstAmount: gstAmount,
    totalAmount: totalAmount,
  };
}

function waNumber(phone) {
  var num = (phone || "").replace(/\D/g, "");
  return num.startsWith("91") ? num : "91" + num;
}

// ---- Build full invoice HTML string -------------------------
function buildInvoiceHTML(inv) {
  var itemRows = (inv.items || [])
    .map(function (i) {
      return (
        "<tr>" +
        "<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb'>" +
        i.treatment +
        "</td>" +
        "<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb;text-align:center'>" +
        i.quantity +
        "</td>" +
        "<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb;text-align:right'>Rs. " +
        Number(i.rate).toLocaleString("en-IN", { minimumFractionDigits: 2 }) +
        "</td>" +
        "<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb;text-align:right'>Rs. " +
        Number(i.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 }) +
        "</td>" +
        "</tr>"
      );
    })
    .join("");

  var discountRow =
    (inv.discountAmount || 0) > 0
      ? "<tr><td>Discount</td><td style='text-align:right;color:#dc2626'>- Rs. " +
        Number(inv.discountAmount).toLocaleString("en-IN", {
          minimumFractionDigits: 2,
        }) +
        "</td></tr>"
      : "";
  var gstRow =
    (inv.gstAmount || 0) > 0
      ? "<tr><td>GST (" +
        (inv.gstPercent || 0) +
        "%)</td><td style='text-align:right'>+ Rs. " +
        Number(inv.gstAmount).toLocaleString("en-IN", {
          minimumFractionDigits: 2,
        }) +
        "</td></tr>"
      : "";
  var dueRow =
    (inv.amountDue || 0) > 0
      ? "<tr><td style='color:#dc2626'>Amount Due</td><td style='text-align:right;color:#dc2626'>Rs. " +
        Number(inv.amountDue).toLocaleString("en-IN", {
          minimumFractionDigits: 2,
        }) +
        "</td></tr>"
      : "";
  var notesBlock = inv.notes
    ? "<div style='background:#f8fafc;border:1px solid #e5e7eb;border-radius:6px;padding:10px 14px;font-size:12px;color:#475569;margin-top:10px'><strong>Notes:</strong> " +
      inv.notes +
      "</div>"
    : "";
  var receiptLine = inv.receiptNumber
    ? "<p>Receipt: " + inv.receiptNumber + "</p>"
    : "";
  var patientExtra =
    (inv.patientAge ? " | Age: " + inv.patientAge : "") +
    (inv.patientGender ? " | " + inv.patientGender : "");

  // Doctor stamp block
  var doctorStamp =
    "<div style='display:flex;justify-content:flex-end;margin-top:28px;'>" +
    "<div style='text-align:center;min-width:180px;'>" +
    "<div style='width:110px;height:110px;border-radius:50%;border:3px solid #1e3a8a;margin:0 auto 10px;display:flex;flex-direction:column;align-items:center;justify-content:center;background:#f0f6ff;'>" +
    "<div style='font-size:11px;font-weight:800;color:#1e3a8a;text-align:center;padding:0 8px;line-height:1.3'>" +
    HOSPITAL_NAME +
    "</div>" +
    "<div style='font-size:22px;margin:4px 0;color:#1e3a8a;'>+</div>" +
    "<div style='font-size:10px;color:#1e3a8a;font-weight:600'>DENTAL SEAL</div>" +
    "</div>" +
    "<div style='border-top:2px solid #1e3a8a;padding-top:6px;font-size:13px;font-weight:700;color:#1e293b'>" +
    (inv.doctorName || "Doctor") +
    "</div>" +
    "<div style='font-size:11px;color:#64748b;margin-top:2px'>Authorised Signatory</div>" +
    "<div style='font-size:11px;color:#64748b'>" +
    HOSPITAL_NAME +
    "</div>" +
    "</div>" +
    "</div>";

  return (
    "<!DOCTYPE html><html><head><meta charset='utf-8'><title>Invoice " +
    inv.invoiceNumber +
    "</title>" +
    "<style>" +
    "body{font-family:Arial,sans-serif;margin:0;padding:0;color:#1e293b;font-size:13px}" +
    ".page{max-width:700px;margin:0 auto;padding:30px 36px}" +
    ".header{background:#1e3a8a;color:#fff;padding:20px 24px;border-radius:8px;margin-bottom:24px;display:flex;justify-content:space-between;align-items:center}" +
    ".header h1{margin:0;font-size:20px}" +
    ".header p{margin:4px 0 0;font-size:11px;opacity:.85}" +
    ".inv-meta{display:flex;justify-content:space-between;margin-bottom:20px;gap:20px;flex-wrap:wrap}" +
    ".box{background:#f8fafc;border:1px solid #e5e7eb;border-radius:8px;padding:12px 16px;flex:1;min-width:180px}" +
    ".box h4{margin:0 0 8px;font-size:11px;color:#94a3b8;text-transform:uppercase;letter-spacing:.5px}" +
    ".box p{margin:2px 0;font-size:13px}" +
    "table{width:100%;border-collapse:collapse;margin-bottom:16px}" +
    "thead tr{background:#1e3a8a;color:#fff}" +
    "thead th{padding:10px;text-align:left;font-size:12px}" +
    ".totals{display:flex;justify-content:flex-end}" +
    ".totals table{width:260px}" +
    ".totals td{padding:5px 10px;font-size:13px}" +
    ".grand{font-weight:700;font-size:15px;color:#1e3a8a;border-top:2px solid #1e3a8a}" +
    ".pay-badge{display:inline-block;padding:4px 12px;border-radius:20px;font-size:12px;font-weight:700}" +
    ".paid{background:#dcfce7;color:#16a34a}.partial{background:#fef9c3;color:#d97706}.unpaid{background:#fee2e2;color:#dc2626}" +
    ".footer{margin-top:20px;border-top:2px solid #1e3a8a;padding-top:14px;text-align:center;font-size:11px;color:#94a3b8}" +
    "@media print{body{padding:0}.page{padding:20px}}" +
    "</style></head><body><div class='page'>" +
    "<div class='header'>" +
    "<div><h1>" +
    HOSPITAL_NAME +
    "</h1><p>" +
    HOSPITAL_ADDRESS +
    "</p><p>" +
    HOSPITAL_PHONE +
    " &nbsp;|&nbsp; " +
    HOSPITAL_GST +
    "</p></div>" +
    "<div style='text-align:right'><div style='font-size:22px;font-weight:800'>INVOICE</div><div style='font-size:15px;margin-top:4px'>" +
    inv.invoiceNumber +
    "</div></div>" +
    "</div>" +
    "<div class='inv-meta'>" +
    "<div class='box'><h4>Patient</h4><p><strong>" +
    inv.patientName +
    "</strong></p><p>" +
    (inv.patientPhone || "") +
    patientExtra +
    "</p></div>" +
    "<div class='box'><h4>Invoice Info</h4><p>Date: <strong>" +
    friendlyDate(inv.invoiceDate) +
    "</strong></p><p>Doctor: " +
    (inv.doctorName || "--") +
    "</p></div>" +
    "<div class='box'><h4>Payment Status</h4><p><span class='pay-badge " +
    inv.paymentStatus +
    "'>" +
    (inv.paymentStatus || "").toUpperCase() +
    "</span></p><p>Method: " +
    (inv.paymentMethod || "--") +
    "</p>" +
    receiptLine +
    "</div>" +
    "</div>" +
    "<table><thead><tr><th>Treatment</th><th style='text-align:center'>Qty</th><th style='text-align:right'>Rate</th><th style='text-align:right'>Amount</th></tr></thead><tbody>" +
    itemRows +
    "</tbody></table>" +
    "<div class='totals'><table>" +
    "<tr><td>Subtotal</td><td style='text-align:right'>Rs. " +
    Number(inv.subtotal || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
    }) +
    "</td></tr>" +
    discountRow +
    gstRow +
    "<tr class='grand'><td>Total</td><td style='text-align:right'>Rs. " +
    Number(inv.totalAmount || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
    }) +
    "</td></tr>" +
    "<tr><td style='color:#16a34a'>Amount Paid</td><td style='text-align:right;color:#16a34a'>Rs. " +
    Number(inv.amountPaid || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
    }) +
    "</td></tr>" +
    dueRow +
    "</table></div>" +
    notesBlock +
    doctorStamp +
    "<div class='footer'><p>Thank you for choosing " +
    HOSPITAL_NAME +
    ". Your smile is our priority.</p></div>" +
    "</div></body></html>"
  );
}

// ---- Open invoice in new tab (for print or share base) ------
function openInvoiceTab(inv) {
  var win = window.open("", "_blank");
  if (!win) return null;
  win.document.write(buildInvoiceHTML(inv));
  win.document.close();
  return win;
}

// ---- Print invoice ------------------------------------------
function printInvoice(inv) {
  var win = openInvoiceTab(inv);
  if (win)
    setTimeout(function () {
      win.print();
    }, 600);
}

// ---- Share invoice on WhatsApp ------------------------------
// Strategy:
//   1. Try Web Share API with PDF blob (works on Android Chrome/mobile)
//   2. Fallback: open the invoice print page + send a WhatsApp text message
//      with a summary so the doctor can copy-paste the link manually
function shareInvoiceWhatsApp(inv) {
  var phone = waNumber(inv.patientPhone || "");

  // Build a plain-text summary to send via WhatsApp
  var msg =
    "Hello " +
    inv.patientName +
    ",\n\n" +
    "Please find your invoice from *" +
    HOSPITAL_NAME +
    "*:\n\n" +
    "Invoice No : " +
    inv.invoiceNumber +
    "\n" +
    "Date       : " +
    friendlyDate(inv.invoiceDate) +
    "\n" +
    "Doctor     : " +
    (inv.doctorName || "--") +
    "\n" +
    "Services   : " +
    (inv.items || [])
      .map(function (i) {
        return i.treatment;
      })
      .join(", ") +
    "\n" +
    "Total      : Rs. " +
    Number(inv.totalAmount || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
    }) +
    "\n" +
    "Paid       : Rs. " +
    Number(inv.amountPaid || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
    }) +
    "\n" +
    ((inv.amountDue || 0) > 0
      ? "Due        : Rs. " +
        Number(inv.amountDue).toLocaleString("en-IN", {
          minimumFractionDigits: 2,
        }) +
        "\n"
      : "") +
    "Status     : " +
    (inv.paymentStatus || "").toUpperCase() +
    "\n\n" +
    "-- " +
    HOSPITAL_NAME +
    "\n" +
    HOSPITAL_PHONE;

  var waUrl = "https://wa.me/" + phone + "?text=" + encodeURIComponent(msg);

  // On mobile: try native share with the invoice HTML as a blob
  if (
    navigator.share &&
    navigator.canShare &&
    typeof window.File !== "undefined" &&
    typeof window.Blob !== "undefined"
  ) {
    try {
      var htmlBlob = new Blob([buildInvoiceHTML(inv)], { type: "text/html" });
      var file = new File(
        [htmlBlob],
        "Invoice-" + inv.invoiceNumber + ".html",
        { type: "text/html" },
      );
      if (navigator.canShare({ files: [file] })) {
        navigator
          .share({
            title: "Invoice " + inv.invoiceNumber + " - " + HOSPITAL_NAME,
            text: msg,
            files: [file],
          })
          .catch(function () {
            // User cancelled or share failed — fallback to WhatsApp URL
            window.open(waUrl, "_blank");
          });
        return;
      }
    } catch (e) {
      // fall through to URL fallback
    }
  }

  // Desktop / unsupported: open invoice in new tab + open WhatsApp with text summary
  openInvoiceTab(inv);
  setTimeout(function () {
    window.open(waUrl, "_blank");
  }, 400);
}

// ---- Shared styles ------------------------------------------
var card = {
  background: "#fff",
  border: "1px solid #e5e7eb",
  borderRadius: "10px",
  padding: "18px 20px",
  boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
};
var labelSt = {
  fontSize: "11px",
  color: "#94a3b8",
  fontWeight: 600,
  textTransform: "uppercase",
  display: "block",
  marginBottom: "4px",
};
var inputSt = {
  width: "100%",
  padding: "8px 10px",
  borderRadius: "7px",
  border: "1px solid #d1d5db",
  fontSize: "13px",
  outline: "none",
  boxSizing: "border-box",
};
var btnPrimary = {
  padding: "9px 20px",
  borderRadius: "8px",
  background: "#1e40af",
  color: "#fff",
  border: "none",
  fontSize: "13px",
  fontWeight: 700,
  cursor: "pointer",
};
var btnGhost = {
  padding: "8px 16px",
  borderRadius: "8px",
  background: "#f1f5f9",
  color: "#374151",
  border: "1px solid #d1d5db",
  fontSize: "13px",
  fontWeight: 600,
  cursor: "pointer",
};

// ---- Patient Picker Modal -----------------------------------
function PatientPickerModal({ patients, onSelect, onClose }) {
  var [q, setQ] = useState("");
  var list = patients.filter(function (p) {
    return (
      (p.name || "").toLowerCase().includes(q.toLowerCase()) ||
      (p.mobile || "").includes(q)
    );
  });

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.5)",
        zIndex: 9000,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "16px",
      }}
    >
      <div
        style={{
          background: "#fff",
          borderRadius: "12px",
          width: "100%",
          maxWidth: "480px",
          maxHeight: "80vh",
          display: "flex",
          flexDirection: "column",
          boxShadow: "0 8px 40px rgba(0,0,0,0.2)",
        }}
      >
        <div
          style={{
            padding: "16px 20px",
            borderBottom: "1px solid #e5e7eb",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <span style={{ fontWeight: 700, fontSize: "15px", color: "#1e293b" }}>
            Select Patient
          </span>
          <button
            onClick={onClose}
            style={{
              background: "none",
              border: "none",
              fontSize: "20px",
              cursor: "pointer",
              color: "#94a3b8",
              lineHeight: 1,
            }}
          >
            x
          </button>
        </div>
        <div
          style={{ padding: "12px 20px", borderBottom: "1px solid #f1f5f9" }}
        >
          <input
            value={q}
            onChange={function (e) {
              setQ(e.target.value);
            }}
            placeholder="Search by name or phone..."
            style={inputSt}
            autoFocus
          />
        </div>
        <div style={{ overflowY: "auto", flex: 1 }}>
          {list.length === 0 ? (
            <div
              style={{
                padding: "30px",
                textAlign: "center",
                color: "#94a3b8",
                fontSize: "13px",
              }}
            >
              No patients found
            </div>
          ) : (
            list.map(function (p) {
              return (
                <div
                  key={p._id}
                  onClick={function () {
                    onSelect(p);
                  }}
                  style={{
                    padding: "12px 20px",
                    borderBottom: "1px solid #f8fafc",
                    cursor: "pointer",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                  }}
                  onMouseEnter={function (e) {
                    e.currentTarget.style.background = "#f0f9ff";
                  }}
                  onMouseLeave={function (e) {
                    e.currentTarget.style.background = "#fff";
                  }}
                >
                  <div>
                    <div
                      style={{
                        fontWeight: 600,
                        fontSize: "14px",
                        color: "#1e293b",
                      }}
                    >
                      {p.name}
                    </div>
                    <div
                      style={{
                        fontSize: "12px",
                        color: "#64748b",
                        marginTop: "2px",
                      }}
                    >
                      {p.mobile}
                      {p.age ? " | Age: " + p.age : ""}
                      {p.gender ? " | " + p.gender : ""}
                    </div>
                  </div>
                  <div style={{ fontSize: "11px", color: "#94a3b8" }}>
                    {(p.visits || []).length} visits
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}

// ---- Invoice Form -------------------------------------------
function InvoiceForm({
  patients,
  doctor,
  invoice,
  onSave,
  onCancel,
  showNotify,
}) {
  var isEdit = !!invoice;
  var [showPicker, setShowPicker] = useState(false);
  var [saving, setSaving] = useState(false);

  var [form, setForm] = useState({
    patientId: "",
    patientName: "",
    patientPhone: "",
    patientAge: "",
    patientGender: "",
    doctorName: (doctor && doctor.name) || "",
    doctorId: (doctor && doctor.doctorId) || "",
    invoiceDate: todayISO(),
    discountType: "flat",
    discountValue: "0",
    gstPercent: "0",
    paymentStatus: "unpaid",
    paymentMethod: "cash",
    amountPaid: "0",
    paymentDate: todayISO(),
    receiptNumber: "",
    upiId: "",
    insuranceProvider: "",
    insuranceClaimNo: "",
    insuranceStatus: "",
    notes: "",
  });

  var [items, setItems] = useState([
    { treatment: "", quantity: "1", rate: "", amount: "0" },
  ]);

  // Populate form when editing
  useEffect(
    function () {
      if (invoice) {
        setForm({
          patientId: invoice.patientId || "",
          patientName: invoice.patientName || "",
          patientPhone: invoice.patientPhone || "",
          patientAge: invoice.patientAge || "",
          patientGender: invoice.patientGender || "",
          doctorName: invoice.doctorName || (doctor && doctor.name) || "",
          doctorId: invoice.doctorId || (doctor && doctor.doctorId) || "",
          invoiceDate: invoice.invoiceDate || todayISO(),
          discountType: invoice.discountType || "flat",
          discountValue: String(invoice.discountValue || 0),
          gstPercent: String(invoice.gstPercent || 0),
          paymentStatus: invoice.paymentStatus || "unpaid",
          paymentMethod: invoice.paymentMethod || "cash",
          amountPaid: String(invoice.amountPaid || 0),
          paymentDate: invoice.paymentDate || todayISO(),
          receiptNumber: invoice.receiptNumber || "",
          upiId: invoice.upiId || "",
          insuranceProvider: invoice.insuranceProvider || "",
          insuranceClaimNo: invoice.insuranceClaimNo || "",
          insuranceStatus: invoice.insuranceStatus || "",
          notes: invoice.notes || "",
        });
        setItems(
          (invoice.items || []).map(function (i) {
            return {
              treatment: i.treatment,
              quantity: String(i.quantity),
              rate: String(i.rate),
              amount: String(i.amount),
            };
          }),
        );
      }
    },
    [invoice, doctor],
  );

  function setF(key, val) {
    setForm(function (f) {
      return Object.assign({}, f, { [key]: val });
    });
  }

  function pickPatient(p) {
    setForm(function (f) {
      return Object.assign({}, f, {
        patientId: p._id,
        patientName: p.name,
        patientPhone: p.mobile || "",
        patientAge: p.age || "",
        patientGender: p.gender || "",
      });
    });
    setShowPicker(false);
  }

  function updateItem(idx, key, val) {
    setItems(function (prev) {
      var arr = prev.map(function (x) {
        return Object.assign({}, x);
      });
      arr[idx][key] = val;
      if (key === "quantity" || key === "rate") {
        var q = parseFloat(key === "quantity" ? val : arr[idx].quantity) || 0;
        var r = parseFloat(key === "rate" ? val : arr[idx].rate) || 0;
        arr[idx].amount = String((q * r).toFixed(2));
      }
      return arr;
    });
  }

  function addItem() {
    setItems(function (p) {
      return p.concat([
        { treatment: "", quantity: "1", rate: "", amount: "0" },
      ]);
    });
  }

  function removeItem(idx) {
    setItems(function (p) {
      return p.filter(function (_, i) {
        return i !== idx;
      });
    });
  }

  var totals = calcTotals(
    items,
    form.discountType,
    form.discountValue,
    form.gstPercent,
  );
  var subtotal = totals.subtotal;
  var discountAmount = totals.discountAmount;
  var gstAmount = totals.gstAmount;
  var totalAmount = totals.totalAmount;
  var amountDue = Math.max(0, totalAmount - (parseFloat(form.amountPaid) || 0));

  async function handleSave() {
    if (!form.patientId) {
      showNotify("Error", "Please select a patient.", true);
      return;
    }
    var emptyItem = items.some(function (i) {
      return !i.treatment || !i.rate;
    });
    if (emptyItem) {
      showNotify(
        "Error",
        "Fill in treatment and rate for all line items.",
        true,
      );
      return;
    }
    setSaving(true);
    try {
      var payload = Object.assign({}, form, {
        discountValue: parseFloat(form.discountValue) || 0,
        gstPercent: parseFloat(form.gstPercent) || 0,
        amountPaid: parseFloat(form.amountPaid) || 0,
        items: items.map(function (i) {
          return {
            treatment: i.treatment,
            quantity: parseFloat(i.quantity) || 1,
            rate: parseFloat(i.rate) || 0,
            amount: parseFloat(i.amount) || 0,
          };
        }),
        subtotal: subtotal,
        discountAmount: discountAmount,
        gstAmount: gstAmount,
        totalAmount: totalAmount,
        amountDue: amountDue,
      });

      // auto payment status
      if (payload.amountPaid >= totalAmount && totalAmount > 0) {
        payload.paymentStatus = "paid";
      } else if (payload.amountPaid > 0) {
        payload.paymentStatus = "partial";
      } else {
        payload.paymentStatus = "unpaid";
      }

      if (isEdit) {
        await api.put("/billing/" + invoice._id, payload);
        showNotify("Saved", "Invoice updated successfully.");
      } else {
        await api.post("/billing", payload);
        showNotify("Created", "Invoice created successfully.");
      }
      onSave();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
    setSaving(false);
  }

  return (
    <div>
      {showPicker && (
        <PatientPickerModal
          patients={patients}
          onSelect={pickPatient}
          onClose={function () {
            setShowPicker(false);
          }}
        />
      )}

      {/* Header */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "20px",
          flexWrap: "wrap",
          gap: "10px",
        }}
      >
        <h3 style={{ margin: 0, color: "#1e293b", fontSize: "17px" }}>
          {isEdit ? "Edit Invoice" : "New Invoice"}
        </h3>
        <div style={{ display: "flex", gap: "8px" }}>
          <button onClick={onCancel} style={btnGhost}>
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            style={Object.assign({}, btnPrimary, { opacity: saving ? 0.7 : 1 })}
          >
            {saving
              ? "Saving..."
              : isEdit
                ? "Update Invoice"
                : "Create Invoice"}
          </button>
        </div>
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(300px,1fr))",
          gap: "16px",
        }}
      >
        {/* Patient */}
        <div style={card}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Patient Details
          </div>
          <button
            onClick={function () {
              setShowPicker(true);
            }}
            style={Object.assign({}, btnGhost, {
              width: "100%",
              marginBottom: "12px",
              textAlign: "left",
            })}
          >
            {form.patientName
              ? form.patientName + " — " + form.patientPhone
              : "Select Patient from Profile..."}
          </button>
          {form.patientName && (
            <div
              style={{
                background: "#f0f9ff",
                border: "1px solid #bae6fd",
                borderRadius: "7px",
                padding: "10px 12px",
                fontSize: "12px",
                color: "#0369a1",
              }}
            >
              <strong>{form.patientName}</strong> &nbsp;|&nbsp;{" "}
              {form.patientPhone}
              {form.patientAge ? " | Age: " + form.patientAge : ""}
              {form.patientGender ? " | " + form.patientGender : ""}
            </div>
          )}
        </div>

        {/* Invoice info */}
        <div style={card}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Invoice Details
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "10px",
            }}
          >
            <div>
              <label style={labelSt}>Invoice Date</label>
              <input
                type="date"
                value={form.invoiceDate}
                onChange={function (e) {
                  setF("invoiceDate", e.target.value);
                }}
                style={inputSt}
              />
            </div>
            <div>
              <label style={labelSt}>Doctor Name</label>
              <input
                value={form.doctorName}
                onChange={function (e) {
                  setF("doctorName", e.target.value);
                }}
                style={inputSt}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Line items */}
      <div style={Object.assign({}, card, { marginTop: "16px" })}>
        <div
          style={{
            fontWeight: 700,
            fontSize: "13px",
            color: "#1e40af",
            marginBottom: "14px",
            textTransform: "uppercase",
            letterSpacing: "0.5px",
          }}
        >
          Treatments / Services
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "3fr 80px 100px 100px 36px",
            gap: "8px",
            marginBottom: "6px",
            padding: "0 2px",
          }}
        >
          {["Treatment", "Qty", "Rate (Rs.)", "Amount", ""].map(
            function (h, i) {
              return (
                <div
                  key={i}
                  style={{
                    fontSize: "11px",
                    color: "#94a3b8",
                    fontWeight: 600,
                    textTransform: "uppercase",
                  }}
                >
                  {h}
                </div>
              );
            },
          )}
        </div>

        {items.map(function (item, idx) {
          return (
            <div
              key={idx}
              style={{
                display: "grid",
                gridTemplateColumns: "3fr 80px 100px 100px 36px",
                gap: "8px",
                marginBottom: "8px",
                alignItems: "center",
              }}
            >
              <div>
                <input
                  list={"tx-list-" + idx}
                  value={item.treatment}
                  onChange={function (e) {
                    updateItem(idx, "treatment", e.target.value);
                  }}
                  placeholder="Type or select treatment..."
                  style={inputSt}
                />
                <datalist id={"tx-list-" + idx}>
                  {DENTAL_TREATMENTS.map(function (t) {
                    return <option key={t} value={t} />;
                  })}
                </datalist>
              </div>
              <input
                type="number"
                min="1"
                value={item.quantity}
                onChange={function (e) {
                  updateItem(idx, "quantity", e.target.value);
                }}
                style={inputSt}
              />
              <input
                type="number"
                min="0"
                value={item.rate}
                onChange={function (e) {
                  updateItem(idx, "rate", e.target.value);
                }}
                placeholder="0"
                style={inputSt}
              />
              <input
                readOnly
                value={fmtMoney(item.amount)}
                style={Object.assign({}, inputSt, {
                  background: "#f8fafc",
                  fontWeight: 600,
                })}
              />
              <button
                onClick={function () {
                  removeItem(idx);
                }}
                disabled={items.length === 1}
                style={{
                  padding: "6px",
                  borderRadius: "6px",
                  background: "#fef2f2",
                  border: "1px solid #fca5a5",
                  color: "#dc2626",
                  cursor: items.length === 1 ? "default" : "pointer",
                  fontSize: "13px",
                  fontWeight: 700,
                }}
              >
                x
              </button>
            </div>
          );
        })}

        <button
          onClick={addItem}
          style={Object.assign({}, btnGhost, {
            marginTop: "6px",
            fontSize: "12px",
          })}
        >
          + Add Treatment
        </button>
      </div>

      {/* Discount / GST / Totals */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))",
          gap: "16px",
          marginTop: "16px",
        }}
      >
        <div style={card}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Discount and Tax
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "10px",
            }}
          >
            <div>
              <label style={labelSt}>Discount Type</label>
              <select
                value={form.discountType}
                onChange={function (e) {
                  setF("discountType", e.target.value);
                }}
                style={inputSt}
              >
                <option value="flat">Flat (Rs.)</option>
                <option value="percent">Percentage (%)</option>
              </select>
            </div>
            <div>
              <label style={labelSt}>Discount Value</label>
              <input
                type="number"
                min="0"
                value={form.discountValue}
                onChange={function (e) {
                  setF("discountValue", e.target.value);
                }}
                style={inputSt}
              />
            </div>
            <div>
              <label style={labelSt}>GST (%)</label>
              <input
                type="number"
                min="0"
                max="100"
                value={form.gstPercent}
                onChange={function (e) {
                  setF("gstPercent", e.target.value);
                }}
                style={inputSt}
              />
            </div>
          </div>
        </div>

        <div style={Object.assign({}, card, { background: "#f8fafc" })}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Summary
          </div>
          {[
            ["Subtotal", fmtMoney(subtotal)],
            ["Discount", "- " + fmtMoney(discountAmount)],
            ["GST", "+ " + fmtMoney(gstAmount)],
          ].map(function (row) {
            return (
              <div
                key={row[0]}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  fontSize: "13px",
                  color: "#475569",
                  marginBottom: "6px",
                }}
              >
                <span>{row[0]}</span>
                <span>{row[1]}</span>
              </div>
            );
          })}
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              fontSize: "16px",
              fontWeight: 800,
              color: "#1e293b",
              borderTop: "2px solid #e5e7eb",
              paddingTop: "8px",
              marginTop: "6px",
            }}
          >
            <span>Total</span>
            <span style={{ color: "#1e40af" }}>{fmtMoney(totalAmount)}</span>
          </div>
        </div>
      </div>

      {/* Payment */}
      <div style={Object.assign({}, card, { marginTop: "16px" })}>
        <div
          style={{
            fontWeight: 700,
            fontSize: "13px",
            color: "#1e40af",
            marginBottom: "12px",
            textTransform: "uppercase",
            letterSpacing: "0.5px",
          }}
        >
          Payment Details
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))",
            gap: "10px",
          }}
        >
          <div>
            <label style={labelSt}>Payment Method</label>
            <select
              value={form.paymentMethod}
              onChange={function (e) {
                setF("paymentMethod", e.target.value);
              }}
              style={inputSt}
            >
              {PAYMENT_METHODS.map(function (m) {
                return (
                  <option key={m.value} value={m.value}>
                    {m.label}
                  </option>
                );
              })}
            </select>
          </div>
          <div>
            <label style={labelSt}>Amount Paid (Rs.)</label>
            <input
              type="number"
              min="0"
              value={form.amountPaid}
              onChange={function (e) {
                setF("amountPaid", e.target.value);
              }}
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Amount Due</label>
            <input
              readOnly
              value={fmtMoney(amountDue)}
              style={Object.assign({}, inputSt, {
                background: "#fef2f2",
                fontWeight: 700,
                color: amountDue > 0 ? "#dc2626" : "#16a34a",
              })}
            />
          </div>
          <div>
            <label style={labelSt}>Payment Date</label>
            <input
              type="date"
              value={form.paymentDate}
              onChange={function (e) {
                setF("paymentDate", e.target.value);
              }}
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Receipt No.</label>
            <input
              value={form.receiptNumber}
              onChange={function (e) {
                setF("receiptNumber", e.target.value);
              }}
              placeholder="e.g. RCP-001"
              style={inputSt}
            />
          </div>
          {form.paymentMethod === "upi" && (
            <div>
              <label style={labelSt}>UPI ID</label>
              <input
                value={form.upiId}
                onChange={function (e) {
                  setF("upiId", e.target.value);
                }}
                placeholder="name@upi"
                style={inputSt}
              />
            </div>
          )}
        </div>
      </div>

      {/* Insurance */}
      <div style={Object.assign({}, card, { marginTop: "16px" })}>
        <div
          style={{
            fontWeight: 700,
            fontSize: "13px",
            color: "#1e40af",
            marginBottom: "12px",
            textTransform: "uppercase",
            letterSpacing: "0.5px",
          }}
        >
          Insurance (Optional)
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))",
            gap: "10px",
          }}
        >
          <div>
            <label style={labelSt}>Insurance Provider</label>
            <input
              value={form.insuranceProvider}
              onChange={function (e) {
                setF("insuranceProvider", e.target.value);
              }}
              placeholder="Provider name"
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Claim Number</label>
            <input
              value={form.insuranceClaimNo}
              onChange={function (e) {
                setF("insuranceClaimNo", e.target.value);
              }}
              placeholder="Claim no."
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Claim Status</label>
            <select
              value={form.insuranceStatus}
              onChange={function (e) {
                setF("insuranceStatus", e.target.value);
              }}
              style={inputSt}
            >
              <option value="">Not Applicable</option>
              <option value="pending">Pending</option>
              <option value="approved">Approved</option>
              <option value="rejected">Rejected</option>
            </select>
          </div>
        </div>
      </div>

      {/* Notes */}
      <div style={Object.assign({}, card, { marginTop: "16px" })}>
        <label style={labelSt}>Notes / Remarks</label>
        <textarea
          value={form.notes}
          onChange={function (e) {
            setF("notes", e.target.value);
          }}
          placeholder="Any additional notes..."
          rows={3}
          style={Object.assign({}, inputSt, { resize: "vertical" })}
        />
      </div>

      {/* Bottom save */}
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          gap: "10px",
          marginTop: "20px",
        }}
      >
        <button onClick={onCancel} style={btnGhost}>
          Cancel
        </button>
        <button
          onClick={handleSave}
          disabled={saving}
          style={Object.assign({}, btnPrimary, { opacity: saving ? 0.7 : 1 })}
        >
          {saving ? "Saving..." : isEdit ? "Update Invoice" : "Create Invoice"}
        </button>
      </div>
    </div>
  );
}

// ---- Invoice List Row ---------------------------------------
function InvoiceRow({ inv, onEdit, onDelete }) {
  var cfg = STATUS_CONFIG[inv.paymentStatus] || STATUS_CONFIG.unpaid;

  return (
    <div
      style={Object.assign({}, card, {
        marginBottom: "10px",
        borderLeft: "4px solid " + cfg.color,
        display: "flex",
        flexWrap: "wrap",
        gap: "12px",
        alignItems: "center",
      })}
    >
      {/* Invoice number + date */}
      <div style={{ flex: "0 0 110px" }}>
        <div style={{ fontSize: "12px", color: "#94a3b8", fontWeight: 600 }}>
          Invoice No.
        </div>
        <div style={{ fontWeight: 700, fontSize: "14px", color: "#1e40af" }}>
          {inv.invoiceNumber}
        </div>
        <div style={{ fontSize: "11px", color: "#94a3b8", marginTop: "2px" }}>
          {friendlyDate(inv.invoiceDate)}
        </div>
      </div>

      {/* Patient + doctor */}
      <div style={{ flex: "1 1 160px" }}>
        <div style={{ fontWeight: 700, fontSize: "14px", color: "#1e293b" }}>
          {inv.patientName}
        </div>
        <div style={{ fontSize: "12px", color: "#64748b" }}>
          {inv.patientPhone}
        </div>
        <div style={{ fontSize: "11px", color: "#94a3b8", marginTop: "2px" }}>
          Dr. {inv.doctorName}
        </div>
      </div>

      {/* Services */}
      <div style={{ flex: "1 1 180px" }}>
        <div style={{ fontSize: "11px", color: "#94a3b8", fontWeight: 600 }}>
          Services
        </div>
        <div style={{ fontSize: "12px", color: "#475569" }}>
          {(inv.items || [])
            .map(function (i) {
              return i.treatment;
            })
            .join(", ")
            .slice(0, 60) || "--"}
        </div>
      </div>

      {/* Amount */}
      <div style={{ flex: "0 0 100px", textAlign: "right" }}>
        <div style={{ fontWeight: 800, fontSize: "15px", color: "#1e293b" }}>
          {fmtMoney(inv.totalAmount)}
        </div>
        {(inv.amountDue || 0) > 0 && (
          <div style={{ fontSize: "11px", color: "#dc2626", fontWeight: 600 }}>
            Due: {fmtMoney(inv.amountDue)}
          </div>
        )}
      </div>

      {/* Status badge */}
      <div style={{ flex: "0 0 auto" }}>
        <span
          style={{
            padding: "3px 10px",
            borderRadius: "12px",
            background: cfg.bg,
            color: cfg.color,
            border: "1px solid " + cfg.color,
            fontSize: "11px",
            fontWeight: 700,
          }}
        >
          {cfg.label}
        </span>
      </div>

      {/* Action buttons */}
      <div
        style={{
          display: "flex",
          gap: "6px",
          flex: "0 0 auto",
          flexWrap: "wrap",
        }}
      >
        {/* Print */}
        <button
          onClick={function () {
            printInvoice(inv);
          }}
          style={Object.assign({}, btnGhost, {
            padding: "5px 12px",
            fontSize: "12px",
          })}
        >
          Print
        </button>

        {/* Share on WhatsApp — like "Send Prescription" in Patients Profile */}
        <button
          onClick={function () {
            shareInvoiceWhatsApp(inv);
          }}
          style={{
            padding: "5px 12px",
            borderRadius: "8px",
            background: "#dcfce7",
            color: "#16a34a",
            border: "1px solid #16a34a",
            fontSize: "12px",
            fontWeight: 700,
            cursor: "pointer",
          }}
          title={
            "Send invoice to " + (inv.patientName || "patient") + " on WhatsApp"
          }
        >
          Send on WhatsApp
        </button>

        {/* Edit */}
        <button
          onClick={function () {
            onEdit(inv);
          }}
          style={Object.assign({}, btnGhost, {
            padding: "5px 12px",
            fontSize: "12px",
          })}
        >
          Edit
        </button>

        {/* Delete */}
        <button
          onClick={function () {
            onDelete(inv._id);
          }}
          style={{
            padding: "5px 10px",
            borderRadius: "8px",
            background: "#fef2f2",
            color: "#dc2626",
            border: "1px solid #fca5a5",
            fontSize: "12px",
            fontWeight: 600,
            cursor: "pointer",
          }}
        >
          Del
        </button>
      </div>
    </div>
  );
}

// ---- Summary Cards ------------------------------------------
function SummaryCards({ summary }) {
  if (!summary) return null;
  var cards = [
    {
      label: "Total Revenue",
      value: fmtMoney(summary.totalRevenue),
      color: "#16a34a",
    },
    {
      label: "This Month",
      value: fmtMoney(summary.monthlyRevenue),
      color: "#2563eb",
    },
    {
      label: "This Week",
      value: fmtMoney(summary.weeklyRevenue),
      color: "#7c3aed",
    },
    { label: "Today", value: fmtMoney(summary.dailyRevenue), color: "#0891b2" },
    {
      label: "Outstanding Dues",
      value: fmtMoney(summary.totalOutstanding),
      color: "#dc2626",
    },
    { label: "Unpaid Invoices", value: summary.unpaidCount, color: "#dc2626" },
    { label: "Partial", value: summary.partialCount, color: "#d97706" },
    { label: "Paid", value: summary.paidCount, color: "#16a34a" },
  ];
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit,minmax(130px,1fr))",
        gap: "10px",
        marginBottom: "24px",
      }}
    >
      {cards.map(function (c) {
        return (
          <div
            key={c.label}
            style={{
              background: "#fff",
              border: "1px solid #e5e7eb",
              borderTop: "3px solid " + c.color,
              borderRadius: "8px",
              padding: "12px",
              textAlign: "center",
              boxShadow: "0 1px 3px rgba(0,0,0,0.05)",
            }}
          >
            <div style={{ fontSize: "18px", fontWeight: 800, color: c.color }}>
              {c.value}
            </div>
            <div
              style={{
                fontSize: "10px",
                color: "#94a3b8",
                fontWeight: 600,
                marginTop: "2px",
              }}
            >
              {c.label}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ---- Main BillingTab ----------------------------------------
export default function BillingTab({ showNotify, doctor }) {
  var [view, setView] = useState("list");
  var [invoices, setInvoices] = useState([]);
  var [patients, setPatients] = useState([]);
  var [summary, setSummary] = useState(null);
  var [loading, setLoading] = useState(true);
  var [editing, setEditing] = useState(null);
  var [search, setSearch] = useState("");
  var [filterStatus, setFilterStatus] = useState("all");
  var [filterPatient, setFilterPatient] = useState("");

  var load = useCallback(
    async function () {
      setLoading(true);
      try {
        var results = await Promise.all([
          api.get("/billing"),
          api.get("/billing/patients"),
          api.get("/billing/summary"),
        ]);
        setInvoices(Array.isArray(results[0]) ? results[0] : []);
        setPatients(Array.isArray(results[1]) ? results[1] : []);
        setSummary(results[2]);
      } catch (err) {
        showNotify("Error", err.message, true);
      }
      setLoading(false);
    },
    [showNotify],
  );

  useEffect(
    function () {
      load();
    },
    [load],
  );

  async function handleDelete(id) {
    if (!window.confirm("Delete this invoice permanently?")) return;
    try {
      await api.delete("/billing/" + id);
      setInvoices(function (p) {
        return p.filter(function (i) {
          return i._id !== id;
        });
      });
      showNotify("Deleted", "Invoice removed.");
      load();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  }

  function handleEdit(inv) {
    setEditing(inv);
    setView("edit");
  }
  function handleNew() {
    setEditing(null);
    setView("new");
  }
  function handleSaved() {
    setView("list");
    setEditing(null);
    load();
  }

  var filtered = invoices.filter(function (inv) {
    var q = search.toLowerCase();
    var matchSearch =
      !q ||
      (inv.patientName || "").toLowerCase().includes(q) ||
      (inv.invoiceNumber || "").toLowerCase().includes(q) ||
      (inv.patientPhone || "").includes(q);
    var matchStatus =
      filterStatus === "all" || inv.paymentStatus === filterStatus;
    var matchPatient = !filterPatient || inv.patientId === filterPatient;
    return matchSearch && matchStatus && matchPatient;
  });

  // Patient totals
  var patientTotals = {};
  invoices.forEach(function (inv) {
    if (!patientTotals[inv.patientId]) {
      patientTotals[inv.patientId] = {
        name: inv.patientName,
        total: 0,
        count: 0,
      };
    }
    patientTotals[inv.patientId].total += inv.totalAmount || 0;
    patientTotals[inv.patientId].count += 1;
  });

  if (view === "new" || view === "edit") {
    return (
      <div style={{ padding: "0 0 40px" }}>
        <InvoiceForm
          patients={patients}
          doctor={doctor}
          invoice={view === "edit" ? editing : null}
          onSave={handleSaved}
          onCancel={function () {
            setView("list");
          }}
          showNotify={showNotify}
        />
      </div>
    );
  }

  return (
    <div style={{ padding: "0 0 40px" }}>
      <SummaryCards summary={summary} />

      {/* Controls */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "10px",
          marginBottom: "16px",
          alignItems: "center",
        }}
      >
        <input
          value={search}
          onChange={function (e) {
            setSearch(e.target.value);
          }}
          placeholder="Search by patient, invoice number, phone..."
          style={Object.assign({}, inputSt, { flex: "1 1 220px" })}
        />
        <select
          value={filterStatus}
          onChange={function (e) {
            setFilterStatus(e.target.value);
          }}
          style={Object.assign({}, inputSt, { width: "auto" })}
        >
          <option value="all">All Statuses</option>
          {Object.keys(STATUS_CONFIG).map(function (k) {
            return (
              <option key={k} value={k}>
                {STATUS_CONFIG[k].label}
              </option>
            );
          })}
        </select>
        <select
          value={filterPatient}
          onChange={function (e) {
            setFilterPatient(e.target.value);
          }}
          style={Object.assign({}, inputSt, {
            width: "auto",
            maxWidth: "200px",
          })}
        >
          <option value="">All Patients</option>
          {patients.map(function (p) {
            return (
              <option key={p._id} value={p._id}>
                {p.name}
              </option>
            );
          })}
        </select>
        <button onClick={load} style={btnGhost}>
          Refresh
        </button>
        <button onClick={handleNew} style={btnPrimary}>
          + New Invoice
        </button>
      </div>

      {loading ? (
        <div
          style={{
            textAlign: "center",
            padding: "40px",
            color: "#94a3b8",
            fontSize: "15px",
          }}
        >
          Loading invoices...
        </div>
      ) : filtered.length === 0 ? (
        <div
          style={{
            textAlign: "center",
            padding: "40px",
            background: "#f8fafc",
            borderRadius: "10px",
            color: "#94a3b8",
            fontSize: "14px",
            border: "1px dashed #e2e8f0",
          }}
        >
          No invoices found. Click "+ New Invoice" to create one.
        </div>
      ) : (
        <>
          <div
            style={{
              fontSize: "12px",
              color: "#94a3b8",
              marginBottom: "10px",
              fontWeight: 600,
            }}
          >
            Showing {filtered.length} invoice(s)
          </div>
          {filtered.map(function (inv) {
            return (
              <InvoiceRow
                key={inv._id}
                inv={inv}
                onEdit={handleEdit}
                onDelete={handleDelete}
              />
            );
          })}
        </>
      )}

      {/* Patient billing history */}
      {Object.keys(patientTotals).length > 0 && (
        <div style={Object.assign({}, card, { marginTop: "28px" })}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "14px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Patient Billing History
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill,minmax(200px,1fr))",
              gap: "10px",
            }}
          >
            {Object.entries(patientTotals)
              .sort(function (a, b) {
                return b[1].total - a[1].total;
              })
              .map(function (entry) {
                var pid = entry[0];
                var data = entry[1];
                return (
                  <div
                    key={pid}
                    onClick={function () {
                      setFilterPatient(pid);
                    }}
                    style={{
                      background: "#f8fafc",
                      borderRadius: "8px",
                      padding: "10px 14px",
                      cursor: "pointer",
                      border: "1px solid #e5e7eb",
                    }}
                    onMouseEnter={function (e) {
                      e.currentTarget.style.borderColor = "#2563eb";
                    }}
                    onMouseLeave={function (e) {
                      e.currentTarget.style.borderColor = "#e5e7eb";
                    }}
                  >
                    <div
                      style={{
                        fontWeight: 600,
                        fontSize: "13px",
                        color: "#1e293b",
                      }}
                    >
                      {data.name}
                    </div>
                    <div
                      style={{
                        fontSize: "12px",
                        color: "#64748b",
                        marginTop: "3px",
                      }}
                    >
                      {data.count} invoice(s)
                    </div>
                    <div
                      style={{
                        fontSize: "14px",
                        fontWeight: 800,
                        color: "#1e40af",
                        marginTop: "4px",
                      }}
                    >
                      {fmtMoney(data.total)}
                    </div>
                  </div>
                );
              })}
          </div>
        </div>
      )}

      {/* Top services */}
      {summary && summary.topServices && summary.topServices.length > 0 && (
        <div style={Object.assign({}, card, { marginTop: "16px" })}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "14px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Top Billed Treatments
          </div>
          {summary.topServices.map(function (s, i) {
            var maxAmt = summary.topServices[0].amount || 1;
            var pct = Math.round((s.amount / maxAmt) * 100);
            return (
              <div key={i} style={{ marginBottom: "10px" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    fontSize: "12px",
                    marginBottom: "4px",
                  }}
                >
                  <span style={{ color: "#334155", fontWeight: 500 }}>
                    {s.name}
                  </span>
                  <span style={{ color: "#1e40af", fontWeight: 700 }}>
                    {fmtMoney(s.amount)}
                  </span>
                </div>
                <div
                  style={{
                    background: "#e5e7eb",
                    borderRadius: "20px",
                    height: "6px",
                  }}
                >
                  <div
                    style={{
                      background: "#1e40af",
                      borderRadius: "20px",
                      height: "6px",
                      width: pct + "%",
                    }}
                  />
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
